// MARK: - Models

enum TransactionType: String, Codable {
    case deposit
    case withdrawal
    case transfer
    case payment
}

enum TransactionStatus: String, Codable {
    case pending
    case completed
    case failed
    case cancelled
}

enum Currency: String, Codable {
    case usd = "USD"
    case eur = "EUR"
    case gbp = "GBP"
}

struct Transaction: Codable, Identifiable {
    let id: UUID
    let type: TransactionType
    let amount: Decimal
    let currency: Currency
    let fromAccountId: String
    let toAccountId: String?
    let description: String
    let timestamp: Date
    var status: TransactionStatus
    let referenceNumber: String
    
    init(type: TransactionType, amount: Decimal, currency: Currency, fromAccountId: String, toAccountId: String? = nil, description: String) {
        self.id = UUID()
        self.type = type
        self.amount = amount
        self.currency = currency
        self.fromAccountId = fromAccountId
        self.toAccountId = toAccountId
        self.description = description
        self.timestamp = Date()
        self.status = .pending
        self.referenceNumber = Self.generateReferenceNumber()
    }
    
    private static func generateReferenceNumber() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        let random = Int.random(in: 1000...9999)
        return "TXN-\(timestamp)-\(random)"
    }
}

struct Account: Codable, Identifiable {
    let id: String
    let accountNumber: String
    let accountHolderName: String
    var balance: Decimal
    let currency: Currency
    var transactions: [Transaction]
    let createdAt: Date
    var isActive: Bool
    
    var maskedAccountNumber: String {
        let suffix = String(accountNumber.suffix(4))
        return "****\(suffix)"
    }
    
    var formattedBalance: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = currency.rawValue
        return formatter.string(from: balance as NSDecimalNumber) ?? "\(balance)"
    }
}

// MARK: - Encryption Service

final class EncryptionService {
    
    static let shared = EncryptionService()
    
    private let keychainServiceName = "com.bankingapp.encryption"
    private let symmetricKeyTag = "com.bankingapp.symmetrickey"
    
    private init() {
        ensureKeyExists()
    }
    
    // MARK: - Symmetric Key Management
    
    private func ensureKeyExists() {
        if retrieveSymmetricKey() == nil {
            let key = SymmetricKey(size: .bits256)
            storeSymmetricKey(key)
        }
    }
    
    private func storeSymmetricKey(_ key: SymmetricKey) {
        let keyData = key.withUnsafeBytes { Data($0) }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServiceName,
            kSecAttrAccount as String: symmetricKeyTag,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        
        if status != errSecSuccess {
            print("Failed to store symmetric key: \(status)")
        }
    }
    
    private func retrieveSymmetricKey() -> SymmetricKey? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServiceName,
            kSecAttrAccount as String: symmetricKeyTag,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let keyData = result as? Data else {
            return nil
        }
        
        return SymmetricKey(data: keyData)
    }
    
    // MARK: - Encryption / Decryption
    
    func encrypt(data: Data) throws -> Data {
        guard let key = retrieveSymmetricKey() else {
            throw EncryptionError.keyNotFound
        }
        
        let sealedBox = try AES.GCM.seal(data, using: key)
        
        guard let combinedData = sealedBox.combined else {
            throw EncryptionError.encryptionFailed
        }
        
        return combinedData
    }
    
    func decrypt(data: Data) throws -> Data {
        guard let key = retrieveSymmetricKey() else {
            throw EncryptionError.keyNotFound
        }
        
        let sealedBox = try AES.GCM.SealedBox(combined: data)
        let decryptedData = try AES.GCM.open(sealedBox, using: key)
        
        return decryptedData
    }
    
    func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw EncryptionError.invalidInput
        }
        return try encrypt(data: data)
    }
    
    func decryptToString(data: Data) throws -> String {
        let decryptedData = try decrypt(data: data)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw EncryptionError.decryptionFailed
        }
        return string
    }
    
    // MARK: - Hashing
    
    func hashData(_ data: Data) -> String {
        let digest = SHA256.hash(data: data)
        return digest.map { String(format: "%02x", $0) }.joined()
    }
    
    func hashString(_ string: String) -> String {
        let data = Data(string.utf8)
        return hashData(data)
    }
    
    // MARK: - HMAC for transaction integrity
    
    func generateHMAC(for data: Data) throws -> Data {
        guard let key = retrieveSymmetricKey() else {
            throw EncryptionError.keyNotFound
        }
        let hmac = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(hmac)
    }
    
    func verifyHMAC(_ mac: Data, for data: Data) throws -> Bool {
        guard let key = retrieveSymmetricKey() else {
            throw EncryptionError.keyNotFound
        }
        let authCode = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(authCode) == mac
    }
}

enum EncryptionError: LocalizedError {
    case keyNotFound
    case encryptionFailed
    case decryptionFailed
    case invalidInput
    
    var errorDescription: String? {
        switch self {
        case .keyNotFound: return "Encryption key not found in keychain."
        case .encryptionFailed: return "Failed to encrypt data."
        case .decryptionFailed: return "Failed to decrypt data."
        case .invalidInput: return "Invalid input provided for encryption."
        }
    }
}

// MARK: - Secure Storage

final class SecureStorageService {
    
    static let shared = SecureStorageService()
    
    private let encryption = EncryptionService.shared
    private let fileManager = FileManager.default
    
    private var storageURL: URL {
        let documents = fileManager.urls(for: .documentDirectory, in: .userDomainMask).first!
        return documents.appendingPathComponent("secure_data")
    }
    
    private init() {
        createStorageDirectoryIfNeeded()
    }
    
    private func createStorageDirectoryIfNeeded() {
        if !fileManager.fileExists(atPath: storageURL.path) {
            try? fileManager.createDirectory(at: storageURL, withIntermediateDirectories: true)
        }
    }
    
    func saveEncrypted<T: Codable>(_ object: T, forKey key: String) throws {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let jsonData = try encoder.encode(object)
        let encryptedData = try encryption.encrypt(data: jsonData)
        
        let fileURL = storageURL.appendingPathComponent(encryption.hashString(key))
        try encryptedData.write(to: fileURL, options: .completeFileProtection)
    }
    
    func loadEncrypted<T: Codable>(_ type: T.Type, forKey key: String) throws -> T {
        let fileURL = storageURL.appendingPathComponent(encryption.hashString(key))
        let encryptedData = try Data(contentsOf: fileURL)
        let decryptedData = try encryption.decrypt(data: encryptedData)
        
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode(type, from: decryptedData)
    }
    
    func deleteEncrypted(forKey key: String) throws {
        let fileURL = storageURL.appendingPathComponent(encryption.hashString(key))
        if fileManager.fileExists(atPath: fileURL.path) {
            try fileManager.removeItem(at: fileURL)
        }
    }
}

// MARK: - Transaction Errors

enum TransactionError: LocalizedError {
    case insufficientFunds(available: Decimal, requested: Decimal)
    case invalidAmount
    case accountNotFound(accountId: String)
    case accountInactive
    case selfTransferNotAllowed
    case dailyLimitExceeded(limit: Decimal)
    case transactionFailed(reason: String)
    case integrityCheckFailed
    case currencyMismatch
    
    var errorDescription: String? {
        switch self {
        case .insufficientFunds(let available, let requested):
            return "Insufficient funds. Available: \(available), Requested: \(requested)"
        case .invalidAmount:
            return "Transaction amount must be greater than zero."
        case .accountNotFound(let accountId):
            return "Account not found: \(accountId)"
        case .accountInactive:
            return "Account is inactive and cannot process transactions."
        case .selfTransferNotAllowed:
            return "Cannot transfer to the same account."
        case .dailyLimitExceeded(let limit):
            return "Daily transaction limit of \(limit) exceeded."
        case .transactionFailed(let reason):
            return "Transaction failed: \(reason)"
        case .integrityCheckFailed:
            return "Transaction integrity verification failed."
        case .currencyMismatch:
            return "Currency mismatch between accounts."
        }
    }
}

// MARK: - Transaction Processor

final class TransactionProcessor {
    
    static let shared = TransactionProcessor()
    
    private let encryption = EncryptionService.shared
    private let secureStorage = SecureStorageService.shared
    
    private let dailyTransactionLimit: Decimal = 50000.00
    private let processingQueue = DispatchQueue(label: "com.bankingapp.transactionprocessor", qos: .userInitiated)
    
    private var accounts: [String: Account] = [:]
    private var transactionLog: [Transaction] = []
    private let accountsLock = NSLock()
    
    private init() {
        loadAccounts()
    }
    
    // MARK: - Account Management
    
    func createAccount(holderName: String, initialBalance: Decimal, currency: Currency) -> Account {
        accountsLock.lock()
        defer { accountsLock.unlock() }
        
        let accountNumber = generateAccountNumber()
        let account = Account(
            id: UUID().uuidString,
            accountNumber: accountNumber,
            accountHolderName: holderName,
            balance: initialBalance,
            currency: currency,
            transactions: [],
            createdAt: Date(),
            isActive: true
        )
        
        accounts[account.id] = account
        saveAccounts()
        
        return account
    }
    
    func getAccount(by id: String) -> Account? {
        accountsLock.lock()
        defer { accountsLock.unlock() }
        return accounts[id]
    }
    
    func getAllAccounts() -> [Account] {
        accountsLock.lock()
        defer { accountsLock.unlock() }
        return Array(accounts.values)
    }
    
    func getBalance(for accountId: String) throws -> Decimal {
        accountsLock.lock()
        defer { accountsLock.unlock() }
        
        guard let account = accounts[accountId] else {
            throw TransactionError.accountNotFound(accountId: accountId)
        }
        
        return account.balance
    }
    
    // MARK: - Transaction Processing
    
    func processDeposit(accountId: String, amount: Decimal, currency: Currency, description: String, completion: @escaping (Result<Transaction, TransactionError>) -> Void) {
        processingQueue.async { [weak self] in
            guard let self = self else { return }
            
            self.accountsLock.lock()
            defer {
                self.accountsLock.unlock()
            }
            
            guard amount > 0 else {
                completion(.failure(.invalidAmount))
                return
            }
            
            guard var account = self.accounts[accountId] else {
                completion(.failure(.accountNotFound(accountId: accountId)))
                return
            }
            
            guard account.isActive else {
                completion(.failure(.accountInactive))
                return
            }
            
            guard account.currency == currency else {
                completion(.failure(.currencyMismatch))
                return
            }
            
            var transaction = Transaction(
                type: .deposit,
                amount: amount,
                currency: currency,
                fromAccountId: accountId,
                description: description
            )
            
            account.balance += amount
            transaction.status = .completed
            account.transactions.append(transaction)
            
            self.accounts[accountId] = account
            self.transactionLog.append(transaction)
            self.saveAccounts()
            self.logTransaction(transaction)
            
            completion(.success(transaction))
        }
    }
    
    func processWithdrawal(accountId: String, amount: Decimal, currency: Currency, description: String, completion: @escaping (Result<Transaction, TransactionError>) -> Void) {
        processingQueue.async { [weak self] in
            guard let self = self else { return }
            
            self.accountsLock.lock()
            defer {
                self.accountsLock.unlock()
            }
            
            guard amount > 0 else {
                completion(.failure(.invalidAmount))
                return
            }
            
            guard var account = self.accounts[accountId] else {
                completion(.failure(.accountNotFound(accountId: accountId)))
                return
            }
            
            guard account.isActive else {
                completion(.failure(.accountInactive))
                return
            }
            
            guard account.currency == currency else {
                completion(.failure(.currencyMismatch))
                return
            }
            
            guard account.balance >= amount else {
                completion(.failure(.insufficientFunds(available: account.balance, requested: amount)))
                return
            }
            
            do {
                try self.checkDailyLimit(accountId: accountId, amount: amount)
            } catch let error as TransactionError {
                completion(.failure(error))
                return
            } catch {
                completion(.failure(.transactionFailed(reason: error.localizedDescription)))
                return
            }
            
            var transaction = Transaction(
                type: .withdrawal,
                amount: amount,
                currency: currency,
                fromAccountId: accountId,
                description: description
            )
            
            account.balance -= amount
            transaction.status = .completed
            account.transactions.append(transaction)
            
            self.accounts[accountId] = account
            self.transactionLog.append(transaction)
            self.saveAccounts()
            self.logTransaction(transaction)
            
            completion(.success(transaction))
        }
    }
    
    func processTransfer(fromAccountId: String, toAccountId: String, amount: Decimal, currency: Currency, description: String, completion: @escaping (Result<Transaction, TransactionError>) -> Void) {
        processingQueue.async { [weak self] in
            guard let self = self else { return }
            
            self.accountsLock.lock()
            defer {
                self.accountsLock.unlock()
            }
            
            guard amount > 0 else {
                completion(.failure(.invalidAmount))
                return
            }
            
            guard fromAccountId != toAccountId else {
                completion(.failure(.selfTransferNotAllowed))
                return
            }
            
            guard var fromAccount = self.accounts[fromAccountId] else {
                completion(.failure(.accountNotFound(accountId: fromAccountId)))
                return
            }
            
            guard var toAccount = self.accounts[toAccountId] else {
                completion(.failure(.accountNotFound(accountId: toAccountId)))
                return
            }
            
            guard fromAccount.isActive else {
                completion(.failure(.accountInactive))
                return
            }
            
            guard toAccount.isActive else {
                completion(.failure(.accountInactive))
                return
            }
            
            guard fromAccount.currency == currency, toAccount.currency == currency else {
                completion(.failure(.currencyMismatch))
                return
            }
            
            guard fromAccount.balance >= amount else {
                completion(.failure(.insufficientFunds(available: fromAccount.balance, requested: amount)))
                return
            }
            
            do {
                try self.checkDailyLimit(accountId: fromAccountId, amount: amount)
            } catch let error as TransactionError {
                completion(.failure(error))
                return
            } catch {
                completion(.failure(.transactionFailed(reason: error.localizedDescription)))
                return
            }
            
            var transaction = Transaction(
                type: .transfer,
                amount: amount,
                currency: currency,
                fromAccountId: fromAccountId,
                toAccountId: toAccountId,
                description: description
            )
            
            fromAccount.balance -= amount
            toAccount.balance += amount
            transaction.status = .completed
            
            fromAccount.transactions.append(transaction)
            toAccount.transactions.append(transaction)
            
            self.accounts[fromAccountId] = fromAccount
            self.accounts[toAccountId] = toAccount
            self.transactionLog.append(transaction)
            self.saveAccounts()
            self.logTransaction(transaction)
            
            completion(.success(transaction))
        }
    }
    
    // MARK: - Transaction History
    
    func getTransactionHistory(for accountId: String) throws -> [Transaction] {
        accountsLock.lock()
        defer { accountsLock.unlock() }
        
        guard let account = accounts[accountId] else {
            throw TransactionError.accountNotFound(accountId: accountId)
        }
        
        return account.transactions.sorted { $0.timestamp > $1.timestamp }
    }
    
    func getTransactionsByDateRange(accountId: String, from startDate: Date, to endDate: Date) throws -> [Transaction] {
        let history = try getTransactionHistory(for: accountId)
        return history.filter { $0.timestamp >= startDate && $0.timestamp <= endDate }
    }
    
    // MARK: - Transaction Integrity
    
    func verifyTransactionIntegrity(_ transaction: Transaction) throws -> Bool {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let transactionData = try encoder.encode(transaction)
        
        let hmac = try encryption.generateHMAC(for: transactionData)
        return try encryption.verifyHMAC(hmac, for: transactionData)
    }
    
    // MARK: - Private Helpers
    
    private func checkDailyLimit(accountId: String, amount: Decimal) throws {
        let calendar = Calendar.current
        let today = calendar.startOfDay(for: Date())
        
        guard let account = accounts[accountId] else {
            throw TransactionError.accountNotFound(accountId: accountId)
        }
        
        let todaysTotal = account.transactions
            .filter { $0.timestamp >= today && ($0.type == .withdrawal || $0.type == .transfer) && $0.status == .completed }
            .reduce(Decimal.zero) { $0 + $1.amount }
        
        if todaysTotal + amount > dailyTransactionLimit {
            throw TransactionError.dailyLimitExceeded(limit: dailyTransactionLimit)
        }
    }
    
    private func generateAccountNumber() -> String {
        let digits = (0..<12).map { _ in String(Int.random(in: 0...9)) }.joined()
        return digits
    }
    
    private func logTransaction(_ transaction: Transaction) {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        if let data = try? encoder.encode(transaction) {
            let hash = encryption.hashData(data)
            print("[TransactionLog] \(transaction.referenceNumber) | Type: \(transaction.type.rawValue) | Status: \(transaction.status.rawValue) | Hash: \(hash)")
        }
    }
    
    private func saveAccounts() {
        let accountsArray = Array(accounts.values)
        try? secureStorage.saveEncrypted(accountsArray, forKey: "banking_accounts")
    }
    
    private func loadAccounts() {
        accountsLock.lock()
        defer { accountsLock.unlock() }
        
        if let loadedAccounts = try? secureStorage.loadEncrypted([Account].self, forKey: "banking_accounts") {
            accounts = Dictionary(uniqueKeysWithValues: loadedAccounts.map { ($0.id, $0) })
        }
    }
}

// MARK: - Account Balance View Model

import SwiftUI

@MainActor
final class AccountViewModel: ObservableObject {
    
    @Published var accounts: [Account] = []
    @Published var selectedAccount: Account?
    @Published var transactions: [Transaction] = []
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?
    @Published var showError: Bool = false
    @Published var successMessage: String?
    @Published var showSuccess: Bool = false
    
    private let processor = TransactionProcessor.shared
    
    func loadAccounts() {
        isLoading = true
        accounts = processor.getAllAccounts()
        isLoading = false
    }
    
    func selectAccount(_ account: Account) {
        selectedAccount = account
        loadTransactions(for: account.id)
    }
    
    func loadTransactions(for accountId: String) {
        do {
            transactions = try processor.getTransactionHistory(for: accountId)
        } catch {
            showError(error.localizedDescription)
        }
    }
    
    func createDemoAccount() {
        let account = processor.createAccount(
            holderName: "John Doe",
            initialBalance: 10000.00,
            currency: .usd
        )
        accounts.append(account)
        selectedAccount = account
    }
    
    func deposit(amount: Decimal, description: String) {
        guard let account = selectedAccount else { return }
        isLoading = true
        
        processor.processDeposit(accountId: account.id, amount: amount, currency: account.currency, description: description) { [weak self] result in
            DispatchQueue.main.async {
                self?.isLoading = false
                switch result {
                case .success(let transaction):
                    self?.handleTransactionSuccess(transaction, message: "Deposit of \(amount) completed successfully.")
                case .failure(let error):
                    self?.showError(error.localizedDescription)
                }
            }
        }
    }
    
    func withdraw(amount: Decimal, description: String) {
        guard let account = selectedAccount else { return }
        isLoading = true
        
        processor.processWithdrawal(accountId: account.id, amount: amount, currency: account.currency, description: description) { [weak self] result in
            DispatchQueue.main.async {
                self?.isLoading = false
                switch result {
                case .success(let transaction):
                    self?.handleTransactionSuccess(transaction, message: "Withdrawal of \(amount) completed successfully.")
                case .failure(let error):
                    self?.showError(error.localizedDescription)
                }
            }
        }
    }
    
    func transfer(toAccountId: String, amount: Decimal, description: String) {
        guard let account = selectedAccount else { return }
        isLoading = true
        
        processor.processTransfer(fromAccountId: account.id, toAccountId: toAccountId, amount: amount, currency: account.currency, description: description) { [weak self] result in
            DispatchQueue.main.async {
                self?.isLoading = false
                switch result {
                case .success(let transaction):
                    self?.handleTransactionSuccess(transaction, message: "Transfer of \(amount) completed successfully.")
                case .failure(let error):
                    self?.showError(error.localizedDescription)
                }
            }
        }
    }
    
    private func handleTransactionSuccess(_ transaction: Transaction, message: String) {
        successMessage = message
        showSuccess = true
        loadAccounts()
        if let selectedAccount = selectedAccount {
            self.selectedAccount = processor.getAccount(by: selectedAccount.id)
            loadTransactions(for: selectedAccount.id)
        }
    }
    
    private func showError(_ message: String) {
        errorMessage = message
        showError = true
    }
}

// MARK: - SwiftUI Views

struct AccountBalanceView: View {
    @StateObject private var viewModel = AccountViewModel()
    
    var body: some View {
        NavigationView {
            VStack(spacing: 0) {
                if viewModel.accounts.isEmpty {
                    emptyStateView
                } else {
                    accountListView
                }
            }
            .navigationTitle("My Accounts")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Button(action: { viewModel.createDemoAccount() }) {
                        Image(systemName: "plus.circle.fill")
                            .font(.title3)
                    }
                }
            }
            .onAppear { viewModel.loadAccounts() }
            .alert("Error", isPresented: $viewModel.showError) {
                Button("OK", role: .cancel) {}
            } message: {
                Text(viewModel.errorMessage ?? "An unknown error occurred.")
            }
            .alert("Success", isPresented: $viewModel.showSuccess) {
                Button("OK", role: .cancel) {}
            } message: {
                Text(viewModel.successMessage ?? "Operation completed successfully.")
            }
        }
        .navigationViewStyle(.stack)
    }
    
    private var emptyStateView: some View {
        VStack(spacing: 20) {
            Spacer()
            Image(systemName: "banknote")
                .font(.system(size: 60))
                .foregroundColor(.gray)
            Text("No Accounts")
                .font(.title2)
                .fontWeight(.semibold)
            Text("Tap + to create a demo account")
                .font(.subheadline)
                .foregroundColor(.secondary)
            Spacer()
        }
    }
    
    private var accountListView: some View {
        List {
            ForEach(viewModel.accounts) { account in
                NavigationLink(destination: AccountDetailView(account: account, viewModel: viewModel)) {
                    AccountCardView(account: account)
                }
            }
        }
        .listStyle(.insetGrouped)
    }
}

