        .navigationTitle("Account Details")
        .navigationBarTitleDisplayMode(.inline)
        .sheet(isPresented: $showTransactionSheet) {
            TransactionFormView(
                account: account,
                transactionType: selectedTransactionType,
                viewModel: viewModel,
                isPresented: $showTransactionSheet
            )
        }
        .onAppear {
            viewModel.selectAccount(account)
        }
    }
    
    private var balanceCard: some View {
        VStack(spacing: 16) {
            Text("Available Balance")
                .font(.subheadline)
                .foregroundColor(.white.opacity(0.8))
            
            Text(viewModel.selectedAccount?.formattedBalance ?? account.formattedBalance)
                .font(.system(size: 36, weight: .bold, design: .rounded))
                .foregroundColor(.white)
            
            HStack {
                Label(account.maskedAccountNumber, systemImage: "creditcard")
                Spacer()
                Label(account.currency.rawValue, systemImage: "dollarsign.circle")
            }
            .font(.caption)
            .foregroundColor(.white.opacity(0.7))
        }
        .padding(24)
        .background(
            LinearGradient(
                colors: [Color.blue, Color.blue.opacity(0.7)],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
        )
        .cornerRadius(16)
        .shadow(color: .blue.opacity(0.3), radius: 10, x: 0, y: 5)
    }
    
    private var actionButtons: some View {
        HStack(spacing: 16) {
            actionButton(title: "Deposit", icon: "arrow.down.circle.fill", color: .green) {
                selectedTransactionType = .deposit
                showTransactionSheet = true
            }
            
            actionButton(title: "Withdraw", icon: "arrow.up.circle.fill", color: .orange) {
                selectedTransactionType = .withdrawal
                showTransactionSheet = true
            }
            
            actionButton(title: "Transfer", icon: "arrow.left.arrow.right.circle.fill", color: .blue) {
                selectedTransactionType = .transfer
                showTransactionSheet = true
            }
        }
    }
    
    private func actionButton(title: String, icon: String, color: Color, action: @escaping () -> Void) -> some View {
        Button(action: action) {
            VStack(spacing: 8) {
                Image(systemName: icon)
                    .font(.title2)
                    .foregroundColor(color)
                Text(title)
                    .font(.caption)
                    .foregroundColor(.primary)
            }
            .frame(maxWidth: .infinity)
            .padding(.vertical, 16)
            .background(Color(.systemGray6))
            .cornerRadius(12)
        }
    }
    
    private var transactionHistorySection: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text("Recent Transactions")
                .font(.headline)
            
            if viewModel.transactions.isEmpty {
                Text("No transactions yet")
                    .font(.subheadline)
                    .foregroundColor(.secondary)
                    .frame(maxWidth: .infinity, alignment: .center)
                    .padding(.vertical, 32)
            } else {
                ForEach(viewModel.transactions) { transaction in
                    TransactionRowView(transaction: transaction, currentAccountId: account.id)
                    if transaction.id != viewModel.transactions.last?.id {
                        Divider()
                    }
                }
            }
        }
        .padding()
        .background(Color(.systemGray6))
        .cornerRadius(12)
    }
}

struct TransactionRowView: View {
    let transaction: Transaction
    let currentAccountId: String
    
    private var isDebit: Bool {
        switch transaction.type {
        case .withdrawal:
            return true
        case .transfer:
            return transaction.fromAccountId == currentAccountId
        case .deposit:
            return false
        case .payment:
            return true
        }
    }
    
    private var transactionIcon: String {
        switch transaction.type {
        case .deposit: return "arrow.down.circle.fill"
        case .withdrawal: return "arrow.up.circle.fill"
        case .transfer: return "arrow.left.arrow.right.circle.fill"
        case .payment: return "creditcard.fill"
        }
    }
    
    private var iconColor: Color {
        switch transaction.type {
        case .deposit: return .green
        case .withdrawal: return .orange
        case .transfer: return .blue
        case .payment: return .purple
        }
    }
    
    var body: some View {
        HStack(spacing: 12) {
            Image(systemName: transactionIcon)
                .font(.title2)
                .foregroundColor(iconColor)
            
            VStack(alignment: .leading, spacing: 4) {
                Text(transaction.description)
                    .font(.subheadline)
                    .fontWeight(.medium)
                    .lineLimit(1)
                
                HStack(spacing: 8) {
                    Text(transaction.type.rawValue.capitalized)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    
                    Text(formatDate(transaction.timestamp))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            
            Spacer()
            
            VStack(alignment: .trailing, spacing: 4) {
                Text("\(isDebit ? "-" : "+")\(formatAmount(transaction.amount))")
                    .font(.subheadline)
                    .fontWeight(.semibold)
                    .foregroundColor(isDebit ? .red : .green)
                
                statusLabel
            }
        }
        .padding(.vertical, 4)
    }
    
    private var statusLabel: some View {
        Text(transaction.status.rawValue.capitalized)
            .font(.caption2)
            .padding(.horizontal, 6)
            .padding(.vertical, 2)
            .background(statusColor.opacity(0.2))
            .foregroundColor(statusColor)
            .cornerRadius(4)
    }
    
    private var statusColor: Color {
        switch transaction.status {
        case .completed: return .green
        case .pending: return .orange
        case .failed: return .red
        case .cancelled: return .gray
        }
    }
    
    private func formatAmount(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = transaction.currency.rawValue
        return formatter.string(from: amount as NSDecimalNumber) ?? "\(amount)"
    }
    
    private func formatDate(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }
}

struct TransactionFormView: View {
    let account: Account
    let transactionType: TransactionType
    @ObservedObject var viewModel: AccountViewModel
    @Binding var isPresented: Bool
    
    @State private var amountString: String = ""
    @State private var description: String = ""
    @State private var toAccountId: String = ""
    
    private var title: String {
        switch transactionType {
        case .deposit: return "Deposit"
        case .withdrawal: return "Withdrawal"
        case .transfer: return "Transfer"
        case .payment: return "Payment"
        }
    }
    
    private var amount: Decimal? {
        Decimal(string: amountString)
    }
    
    private var isValid: Bool {
        guard let amount = amount, amount > 0, !description.isEmpty else { return false }
        if transactionType == .transfer && toAccountId.isEmpty { return false }
        return true
    }
    
    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("Transaction Details")) {
                    HStack {
                        Text("Type")
                        Spacer()
                        Text(title)
                            .foregroundColor(.secondary)
                    }
                    
                    HStack {
                        Text("From Account")
                        Spacer()
                        Text(account.maskedAccountNumber)
                            .foregroundColor(.secondary)
                    }
                    
                    if transactionType == .transfer {
                        Picker("To Account", selection: $toAccountId) {
                            Text("Select Account").tag("")
                            ForEach(viewModel.accounts.filter { $0.id != account.id }) { acc in
                                Text("\(acc.accountHolderName) - \(acc.maskedAccountNumber)").tag(acc.id)
                            }
                        }
                    }
                }
                
                Section(header: Text("Amount")) {
                    HStack {
                        Text(account.currency.rawValue)
                            .foregroundColor(.secondary)
                        TextField("0.00", text: $amountString)
                            .keyboardType(.decimalPad)
                            .multilineTextAlignment(.trailing)
                    }
                    
                    if transactionType == .withdrawal || transactionType == .transfer {
                        HStack {
                            Text("Available Balance")
                                .font(.caption)
                                .foregroundColor(.secondary)
                            Spacer()
                            Text(account.formattedBalance)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                }
                
                Section(header: Text("Description")) {
                    TextField("Enter description", text: $description)
                }
                
                Section {
                    Button(action: submitTransaction) {
                        HStack {
                            Spacer()
                            if viewModel.isLoading {
                                ProgressView()
                                    .tint(.white)
                            } else {
                                Text("Confirm \(title)")
                                    .fontWeight(.semibold)
                            }
                            Spacer()
                        }
                    }
                    .disabled(!isValid || viewModel.isLoading)
                    .listRowBackground(isValid ? Color.blue : Color.gray.opacity(0.3))
                    .foregroundColor(.white)
                }
            }
            .navigationTitle(title)
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") {
                        isPresented = false
                    }
                }
            }
        }
    }
    
    private func submitTransaction() {
        guard let amount = amount else { return }
        
        switch transactionType {
        case .deposit:
            viewModel.deposit(amount: amount, description: description)
        case .withdrawal:
            viewModel.withdraw(amount: amount, description: description)
        case .transfer:
            viewModel.transfer(toAccountId: toAccountId, amount: amount, description: description)
        case .payment:
            viewModel.withdraw(amount: amount, description: description)
        }
        
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
            isPresented = false
        }
    }
}

